{"code": "import json
import pprint

# Get all query_db results for NYSE symbols
nyse_results = []

# Check all local variables for query_db results
for key in locals().keys():
    if 'query_db' in key:
        try:
            value = locals()[key]
            if isinstance(value, list) and value and 'Symbol' in str(value):
                nyse_results.extend(value)
        except:
            pass

print(f"Found {len(nyse_results)} symbols")
nyse_symbols = []
for item in nyse_results:
    if isinstance(item, dict):
        symbol = item.get('Symbol', '')
        if symbol and symbol not in nyse_symbols:
            nyse_symbols.append(symbol)

print(f"Total unique NYSE symbols: {len(nyse_symbols)}")
print("First 20 symbols:", nyse_symbols[:20])

# Now get stocktrade tables
stocktrade_tables = None
for key in locals().keys():
    if 'list_db' in key:
        try:
            value = locals()[key]
            if isinstance(value, list) and value:
                stocktrade_tables = value
                print(f"Found stocktrade database with {len(stocktrade_tables)} tables")
                break
        except:
            pass

print("__RESULT__:")
print(json.dumps({
    "nyse_symbols": nyse_symbols,
    "stocktrade_tables": stocktrade_tables[:20] if stocktrade_tables else None,
    "stocktrade_count": len(stocktrade_tables) if stocktrade_tables else 0
}))"}

